insert into public.cases (id, slug, titulo, tema, dificuldade, premium, contexto, pergunta, opcoes, melhor_opcao_id, trust_level) values
  ('c1', 'caso-lombar-iniciante', 'Aluna iniciante com histórico de dor lombar', 'Coluna e core', 'Iniciante', false, 'Mariana, 34 anos, sedentária há 2 anos. Primeira semana de treino. Refere insegurança com barra livre. Sala equipada com máquinas, halteres e polias.', 'Qual escolha inicial para membros inferiores tende a ser mais prudente?', '[{"id":"a","texto":"Agachamento livre com barra desde a primeira sessão","correta":false,"analise":"O agachamento livre é tecnicamente exigente e impõe demanda relevante sobre a coluna; introduzi-lo já na primeira semana, com insegurança relatada, tende a ser precoce.","criterio":"Ignora a adequação ao nível técnico e o histórico de dor lombar.","lembrar":"Padrões complexos costumam render mais depois que a base de controle e confiança está construída."},{"id":"b","texto":"Leg press 45° com amplitude confortável e cadência controlada","correta":true,"analise":"O leg press guia a trajetória e, em geral, reduz a demanda lombar, permitindo aprender o padrão de agachar com menor custo técnico — coerente com o nível e o histórico dela.","criterio":"Considera nível iniciante, insegurança e histórico lombar.","lembrar":"Começar por uma variação guiada não é ''menos'' — é construir base para progredir com segurança."},{"id":"c","texto":"Stiff com barra para fortalecer a lombar rapidamente","correta":false,"analise":"O stiff exige boa dobradiça de quadril e controle de coluna sob carga; para uma iniciante com histórico lombar, tende a expor a região antes da hora.","criterio":"Ignora o pré-requisito técnico e o contexto de dor.","lembrar":"Fortalecer a cadeia posterior é útil, mas a escolha do exercício depende do preparo atual."}]'::jsonb, 'b', 'cuidado de segurança'),
  ('c2', 'caso-ombro-supino', 'Ombro sensível pedindo peito', 'Ombro', 'Intermediário', false, 'Diego, 41 anos, treina há 3 anos. Quer manter treino de peito. Já executa supino reto com barra há meses, mas relata desconforto pontual na descida.', 'Como ajustar o treino de peito respeitando o ombro?', '[{"id":"a","texto":"Manter o supino reto com barra e aumentar a carga para ''fortalecer'' o ombro","correta":false,"analise":"Aumentar carga sobre um desconforto existente tende a agravar o quadro; a barra também fixa a trajetória, limitando o ajuste fino da amplitude.","criterio":"Ignora o sinal de desconforto e a liberdade articular necessária.","lembrar":"Dor não é sinal para adicionar carga — é sinal para investigar e ajustar."},{"id":"b","texto":"Suspender qualquer exercício de peito por tempo indeterminado","correta":false,"analise":"Interromper tudo pode ser conservador demais quando há alternativas que respeitam a amplitude tolerável; nem sempre é necessário zerar o estímulo.","criterio":"Ignora que existe caminho intermediário entre ''forçar'' e ''parar''.","lembrar":"Adaptar costuma ser mais sustentável do que simplesmente remover."},{"id":"c","texto":"Trocar para supino com halteres e ajustar amplitude ao conforto do ombro","correta":true,"analise":"Os halteres dão liberdade articular e permitem regular a amplitude à tolerância do ombro, em geral mantendo o estímulo no peitoral com menor incômodo.","criterio":"Considera a liberdade de trajetória e a amplitude individual.","lembrar":"Quando a barra incomoda, variações com halteres costumam permitir treinar dentro do conforto."}]'::jsonb, 'c', 'tendência prática'),
  ('c3', 'caso-idoso-forca', 'Idoso ativo buscando força funcional', 'Idoso ativo', 'Iniciante', false, 'Sr. Antônio, 68 anos, sem doenças de base relevantes. Treina 2x por semana. Já tolera bem exercícios em máquina e quer ''ter mais firmeza'' no dia a dia.', 'Qual direção de prescrição tende a favorecer a funcionalidade?', '[{"id":"a","texto":"Somente exercícios isolados em máquina, sem padrões multiarticulares","correta":false,"analise":"Máquinas são úteis e seguras, mas restringir-se a isolados tende a limitar a transferência para tarefas do dia a dia, que envolvem padrões integrados.","criterio":"Ignora o objetivo de funcionalidade (transferência para a vida diária).","lembrar":"O objetivo do aluno orienta a seleção — funcionalidade pede padrões integrados."},{"id":"b","texto":"Introduzir padrões funcionais progressivos (ex.: sentar-levantar assistido, leg press) além de isolados","correta":true,"analise":"Combinar padrões multiarticulares progressivos com isolados, respeitando a boa tolerância dele, em geral favorece força aplicável ao cotidiano.","criterio":"Alinha meio (exercícios) ao fim (funcionalidade) e ao nível dele.","lembrar":"Progressão funcional pode e deve começar simples — o importante é a direção."},{"id":"c","texto":"Priorizar cargas máximas para ganhar força o mais rápido possível","correta":false,"analise":"Buscar cargas máximas de imediato tende a ser imprudente para um iniciante nesse contexto; a prioridade costuma ser padrão, controle e consistência.","criterio":"Ignora a progressão adequada e o perfil de risco.","lembrar":"Velocidade de progressão deve respeitar o preparo — pressa costuma custar caro."}]'::jsonb, 'b', 'regra pedagógica'),
  ('c4', 'caso-hipertrofia-costas', 'Hipertrofia de costas — puxada vs remada', 'Progressão de carga', 'Intermediário', true, 'Rafaela, 27 anos, intermediária. Já domina remada baixa e puxada alta. Treino de 60 min com máquinas, barra, halteres e polias. Quer costas mais completas.', 'Como estruturar o estímulo para costas mais completas?', '[{"id":"a","texto":"Fazer só puxadas verticais, pois ''costas é dorsal''","correta":false,"analise":"Puxadas verticais enfatizam a largura, mas negligenciar o puxar horizontal tende a deixar a espessura (região média) subestimulada.","criterio":"Ignora que direções diferentes de puxada estimulam regiões distintas.","lembrar":"Costas ''completas'' pedem tanto puxar vertical quanto horizontal."},{"id":"b","texto":"Repetir o mesmo exercício de sempre com muito mais carga","correta":false,"analise":"Só aumentar carga no mesmo padrão tende a ignorar o princípio da variação de estímulo e a lacuna de espessura que ela quer preencher.","criterio":"Ignora a especificidade do objetivo (regiões distintas das costas).","lembrar":"Mais carga nem sempre é mais resultado — a seleção do padrão importa."},{"id":"c","texto":"Combinar puxar vertical (largura) e puxar horizontal (espessura), progredindo carga com técnica","correta":true,"analise":"Cobrir as duas direções de puxada, com progressão de carga preservando a técnica, em geral estimula largura e espessura de forma mais completa.","criterio":"Alinha a seleção de exercícios à especificidade do objetivo.","lembrar":"Pense em direções de movimento, não apenas em ''mais um exercício de costas''."}]'::jsonb, 'c', 'princípio biomecânico'),
  ('c5', 'caso-retorno-joelho', 'Retorno pós-cirurgia de menisco', 'Retorno pós-lesão', 'Avançado', true, 'Camila, 30 anos, corredora amadora. Fisioterapia concluída. Médico liberou fortalecimento progressivo respeitando amplitude. Sem dor em atividades diárias.', 'Como conduzir o fortalecimento de forma prudente?', '[{"id":"a","texto":"Retomar direto agachamento profundo com carga alta, já que ''está liberada''","correta":false,"analise":"Liberação para fortalecimento progressivo não é sinônimo de carga máxima e amplitude total imediatas; pular etapas tende a ser arriscado no retorno.","criterio":"Ignora a progressão de amplitude e carga recomendada.","lembrar":"''Liberado'' define um ponto de partida, não um atalho para o pico."},{"id":"b","texto":"Iniciar com amplitudes indolores e progressão gradual (ex.: leg press/cadeira extensora controlados), monitorando resposta","correta":true,"analise":"Trabalhar dentro de amplitudes indolores, progredindo gradualmente e observando a resposta do joelho, em geral respeita a orientação médica e o estágio do retorno.","criterio":"Considera amplitude tolerável, progressão e monitoramento.","lembrar":"No retorno, a resposta do tecido guia a progressão — não o calendário nem o ego."},{"id":"c","texto":"Evitar qualquer exercício de perna por mais alguns meses por precaução","correta":false,"analise":"Com liberação médica e ausência de dor, evitar todo estímulo tende a ser conservador demais e pode atrasar a readaptação de força.","criterio":"Ignora que o estímulo progressivo faz parte do retorno.","lembrar":"Cautela excessiva também tem custo — o meio-termo progressivo costuma ser melhor."}]'::jsonb, 'b', 'cuidado de segurança'),
  ('c6', 'caso-core-lombar-atleta', 'Core para atleta com histórico lombar', 'Coluna e core', 'Avançado', true, 'Bruno, 29 anos, jogador de futebol amador. Já treina há anos; sala completa disponível; sem quadro agudo, mas relata episódios antigos de lombalgia sob fadiga.', 'Que abordagem de core tende a ser mais adequada ao contexto dele?', '[{"id":"a","texto":"Priorizar exercícios de estabilização e anti-movimento (ex.: prancha, anti-rotação), progredindo a demanda","correta":true,"analise":"Para um histórico de lombalgia sob fadiga, treinar a capacidade de resistir a movimento (estabilização/anti-rotação) em geral favorece o controle sob demanda esportiva.","criterio":"Considera o histórico lombar e a função do core no esporte.","lembrar":"Core costuma render mais como ''estabilizador'' do que como ''flexionador'' repetitivo."},{"id":"b","texto":"Grandes volumes de abdominal com flexão repetida de coluna","correta":false,"analise":"Volumes altos de flexão repetida de coluna tendem a não ser a melhor escolha para quem tem histórico de lombalgia, especialmente sob fadiga.","criterio":"Ignora o histórico e o tipo de demanda que o core cumpre no esporte.","lembrar":"Repetir flexão de coluna não é sinônimo de ''core forte''."},{"id":"c","texto":"Ignorar o core e focar apenas em força de membros","correta":false,"analise":"Negligenciar o core tende a deixar uma lacuna importante para quem depende de estabilidade sob fadiga em campo.","criterio":"Ignora a demanda específica do esporte e o histórico.","lembrar":"Lacunas de estabilidade costumam aparecer justamente quando a fadiga chega."}]'::jsonb, 'a', 'tendência prática')
insert into public.tracks (id, slug, nome, descricao, nivel, lessons) values
  ('t1', 'fundamentos-da-prescricao', 'Fundamentos da prescrição', 'Como decidir e justificar antes de montar qualquer treino.', 'Iniciante', '[{"id":"l1","titulo":"O que é decidir na prescrição","tipo":"conceito","duracao":"4 min"},{"id":"l2","titulo":"Objetivo orienta a escolha","tipo":"conceito","duracao":"5 min"},{"id":"l3","titulo":"Ler a execução: Leg press 45°","tipo":"lab","ref":"leg-press-45","duracao":"6 min"},{"id":"l4","titulo":"Nível técnico e progressão","tipo":"conceito","duracao":"5 min"},{"id":"l5","titulo":"Restrições e cautela","tipo":"conceito","duracao":"5 min"},{"id":"l6","titulo":"Caso: iniciante com dor lombar","tipo":"caso","ref":"caso-lombar-iniciante","duracao":"7 min"},{"id":"l7","titulo":"Equipamento disponível na decisão","tipo":"conceito","duracao":"4 min"},{"id":"l8","titulo":"Fechando o raciocínio","tipo":"conceito","duracao":"5 min"}]'::jsonb),
  ('t2', 'membros-inferiores-em-profundidade', 'Membros inferiores em profundidade', 'Do leg press ao agachamento livre: quando escolher cada um.', 'Intermediário', '[{"id":"l1","titulo":"Mapa dos padrões de perna","tipo":"conceito","duracao":"5 min"},{"id":"l2","titulo":"Análise: Leg press 45°","tipo":"lab","ref":"leg-press-45","duracao":"6 min"},{"id":"l3","titulo":"Análise: Agachamento livre","tipo":"lab","ref":"agachamento-livre","duracao":"7 min"},{"id":"l4","titulo":"Dobradiça de quadril: Stiff","tipo":"lab","ref":"levantamento-terra-romeno","duracao":"6 min"},{"id":"l5","titulo":"Caso: força funcional no idoso","tipo":"caso","ref":"caso-idoso-forca","duracao":"6 min"},{"id":"l6","titulo":"Quando guiar, quando soltar","tipo":"conceito","duracao":"5 min"}]'::jsonb),
  ('t3', 'ombro-seguro', 'Ombro seguro e forte', 'Empurrar e puxar respeitando a articulação mais móvel do corpo.', 'Intermediário', '[{"id":"l1","titulo":"Por que o ombro é sensível","tipo":"conceito","duracao":"5 min"},{"id":"l2","titulo":"Análise: Supino reto com barra","tipo":"lab","ref":"supino-reto-barra","duracao":"6 min"},{"id":"l3","titulo":"Controle escapular","tipo":"conceito","duracao":"5 min"},{"id":"l4","titulo":"Análise: Desenvolvimento de ombros","tipo":"lab","ref":"desenvolvimento-ombros","duracao":"6 min"},{"id":"l5","titulo":"Caso: ombro sensível pedindo peito","tipo":"caso","ref":"caso-ombro-supino","duracao":"7 min"}]'::jsonb)
insert into public.library_entries (id, termo, categoria, resumo, detalhe, ver_exercicio) values
  ('b1', 'Objetivo orienta a escolha', 'Princípios de decisão', 'A meta do aluno é o primeiro filtro de seleção do exercício.', 'Antes de escolher entre variações, defina o objetivo (hipertrofia, força, resistência, retorno, aprendizado). Ele orienta a direção do movimento, a faixa de esforço e o quanto a técnica pesa. Em geral, meio (exercício) deve servir ao fim (objetivo) — não o contrário.', null),
  ('b2', 'Adequação ao nível técnico', 'Princípios de decisão', 'O melhor exercício também é o que a pessoa consegue executar bem hoje.', 'Um padrão avançado mal executado tende a render menos e a expor mais do que uma variação simples bem feita. Ajuste a complexidade ao nível atual e progrida conforme o controle melhora.', null),
  ('b3', 'Equipamento na decisão', 'Princípios de decisão', 'A melhor recomendação precisa ser executável com o que há disponível.', 'De nada adianta a variação ''ideal'' se o equipamento não existe na sala. Considere o disponível e escolha a melhor opção viável — às vezes a segunda melhor executável supera a primeira inacessível.', null),
  ('b4', 'Dobradiça de quadril', 'Biomecânica', 'Movimento que vem do quadril indo para trás, com coluna neutra.', 'A dissociação entre quadril e coluna permite trabalhar a cadeia posterior reduzindo a carga passiva na lombar. É a base de exercícios como o levantamento terra romeno (stiff).', 'levantamento-terra-romeno'),
  ('b5', 'Valgo dinâmico do joelho', 'Biomecânica', 'Colapso do joelho para dentro sob carga.', 'Quando o joelho foge da linha do pé em direção medial, aumenta o estresse em estruturas mediais. Em geral, treinar o controle (joelho acompanhando o pé) tende a reduzir desconforto relatado.', 'afundo-passada'),
  ('b6', 'Controle escapular', 'Biomecânica', 'Estabilizar as escápulas dá base segura para empurrar e puxar.', 'Retração e depressão escapular (''encaixe'') criam uma base estável no supino e melhoram o recrutamento nas puxadas. É um pré-requisito de segurança para o ombro.', 'supino-reto-barra'),
  ('b7', 'Ativação vs. eficiência', 'Fisiologia', 'Recrutar muito um músculo não é o único critério de um bom exercício.', 'Alta ativação de um alvo é desejável, mas eficiência considera também demanda articular, complexidade e transferência. Um índice combina esses fatores para orientar a decisão.', null),
  ('b8', 'Tempo sob tensão', 'Fisiologia', 'A cadência influencia o estímulo, não só a carga.', 'Controlar a fase excêntrica aumenta o tempo sob tensão e, em geral, favorece o aprendizado técnico e o estímulo de hipertrofia com cargas mais conservadoras.', null),
  ('b9', 'Demanda lombar', 'Segurança', 'Quanto o exercício exige da coluna lombar sob carga.', 'Exercícios com alta demanda lombar pedem mais controle e podem não ser a primeira escolha em contextos de dor. Variações guiadas tendem a reduzir essa demanda.', 'leg-press-45'),
  ('b10', 'Amplitude indolor', 'Segurança', 'No retorno pós-lesão, a amplitude tolerável guia a progressão.', 'Trabalhar dentro de amplitudes sem dor, progredindo gradualmente e monitorando a resposta, em geral respeita o estágio do retorno. A resposta do tecido guia — não o calendário.', null),
  ('b11', 'Anti-movimento (core)', 'Biomecânica', 'Resistir ao movimento costuma treinar o core melhor que flexioná-lo.', 'Padrões de estabilização e anti-rotação treinam a função do core de resistir a forças — em geral mais transferível ao esporte do que grandes volumes de flexão repetida de coluna.', null),
  ('b12', 'Linguagem prudente', 'Glossário', '''Tende a'', ''em geral'', ''depende do contexto'' — por quê.', 'Respostas em ciências do exercício dependem do indivíduo e da execução. A linguagem prudente comunica tendência, não certeza absoluta, e reforça que o conteúdo é educacional — não substitui avaliação profissional individualizada.', null)
